import com.xuenn.bet188.revamp.model.data.OAuthUserData
import com.xuenn.bet188.revamp.model.data.RegisterData
import com.xuenn.bet188.revamp.utils.AndroidUtils
import com.xuenn.bet188.revamp.utils.CommonUtils
import com.xuenn.bet188.revamp.model.data.UiStr
import com.xuenn.bet188.revamp.model.data.repo.StringsRepository
import com.xuenn.bet188.revamp.utils.disableCopyPaste
import com.xuenn.bet188.revamp.utils.hideKeyboard
import com.xuenn.bet188.revamp.utils.oauth.FacebookOAuthHelper
import com.xuenn.bet188.revamp.utils.oauth.FacebookOAuthUtil
import com.xuenn.bet188.revamp.view.base.BaseActivityOptions
import com.xuenn.bet188.revamp.view.base.BaseBindingHeaderActivity
import com.xuenn.bet188.revamp.viewmodel.RegisterViewModel
import com.xuenn.bet188.revamp.widget.BottomNavigationView
import org.koin.androidx.viewmodel.ext.android.viewModel
import java.util.Calendar


class RegisterTypeSelectActivity : BaseBindingHeaderActivity<ActivityRegisterTypeSelectBinding>() {

    private val mViewModel: RegisterViewModel by viewModel()

    private var isEmailEdited: Boolean = false

    override fun getActivityID(): Int {
        return ConstantsBet188.BOTTOM_NAVIGATION_ICON_DEFAULT
    }

    override fun getLayHeaderBinding(): ViewPageHeaderBinding? {
        return binding.layHeader.headerBinding
    }

    override fun getBottomNavigationView(): BottomNavigationView? {
        return null
    }

    override fun getContentView(): Int {
        return R.layout.activity_register_type_select
    }

    override fun onCreateViewBuilder(): BaseActivityOptions.Builder? {
        return super.onCreateViewBuilder()?.setLogoVisible(true)?.setLogoIcon(StyleManager.logoIcon)?.setMenuVisible(true)?.setMarqueeEnable(false)?.setBottomNavigationBarVisible(false)
    }

    override fun initData() {
        super.initData()

        mViewModel.init(this, false)
        mViewModel.progressDialogObservable.observe(this) { isShow ->
            if (isShow) showLoadingDialog() else dismissLoadingDialog()
        }

        binding.vm = mViewModel
    }

    override fun initView() {
        super.initView()
        getHeaderLoginBtn()!!.visibility = View.VISIBLE
        getHeaderLoginBtn()!!.setOnClickListener { finish() }

        binding.constraintLayout.setOnClickListener { binding.scrollView.clearFocus() }  //for force check affId

        // Disable copy paste for EditText
        binding.email.disableCopyPaste()

        binding.email.addTextChangedListener(object : TextWatcher {
            override fun beforeTextChanged(s: CharSequence, start: Int, count: Int, after: Int) {
                binding.emailLayout.error = ""
            }

            override fun onTextChanged(s: CharSequence, start: Int, before: Int, count: Int) {}
            override fun afterTextChanged(editable: Editable) {
                isEmailEdited = true
                val inputStr = editable.toString().trim()
                if (!CommonUtils.isEmailFormatValid(inputStr)) {
                    binding.emailLayout.error = StringsRepository.getString(UiStr.TIPJOINUSVALIDEMAIL)
                }

                checkIsEnableContinueBtn()
            }
        })

        binding.email.setOnFocusChangeListener { _, hasFocus ->
            if (!hasFocus && isEmailEdited) {
                if ((binding.email.text!!.isEmpty())) binding.emailLayout.error =
                    StringsRepository.getString(UiStr.HELPJOINUSREQUIRED)
            }
        }

        //btn
        binding.btnContinue.setOnClickListener {
            AndroidUtils.hideKeyboard(this)

            finish()

            RegisterActivity.launch(
                this, RegisterData(
                    email = binding.email.text.toString()
                )
            )
        }

        binding.googleLayout.btnGoogle.setOnClickListener {
            AndroidUtils.hideKeyboard(this)

            mViewModel.performGoogleSignIn(this@RegisterTypeSelectActivity)
        }

        binding.facebookLayout.btnFacebook.setOnClickListener {
            hideKeyboard(binding.facebookLayout.btnFacebook)

            FacebookOAuthHelper.launchSignIn(
                this@RegisterTypeSelectActivity,
                Calendar.getInstance().timeInMillis,
                object : IFacebookOAuthListener {
                    override fun facebookOAuthInfo(userInfo: FacebookOAuthUtil.FacebookUserInfo) {
                        OAuthRegisterActivity.launch(
                            this@RegisterTypeSelectActivity, OAuthUserData(
                                oAuthType = Constants.OAuthType.Facebook,
                                oAuthEmail = userInfo.email,
                                oAuthId = userInfo.oAuthIdForSPI,
                                oAuthName = userInfo.name,
                                oAuthCustomData1 = userInfo.facebookAppId
                            )
                        )
                    }

                    override fun setProgressStatus(isInProgress: Boolean) {
                        mViewModel.progressDialogObservable.value = isInProgress
                    }

                    override fun launchFail(e: Exception) {
                        mViewModel.launchFail(e)

                        if (e !is FacebookOAuthUtil.FacebookCancelException) {
                            DialogUtil.showSimpleDialog(
                                this@RegisterTypeSelectActivity,
                                StringsRepository.getString(UiStr.TXTLOGINFAIL),
                                e.message,
                                StringsRepository.getString(UiStr.TXTBTNCOMOK),
                                0
                            )
                        }
                    }

                    override fun reachOAuthLimit(context: Context) {
                        mViewModel.reachOAuthLimit(context)
                    }
                })
        }

        binding.footerView.setDataView(FooterParameter(this))
    }

    override fun onResume() {
        super.onResume()
        mViewModel.initOAuthRecord(this)
    }

    override fun onBaseMenuClick() {
        binding.scrollView.clearFocus()  //for force check affId
        super.onBaseMenuClick()
    }

    fun checkIsEnableContinueBtn() {
        binding.btnContinue.isEnabled =
            (!TextUtils.isEmpty(binding.email.text)
                    && TextUtils.isEmpty(binding.emailLayout.error))
    }

    companion object {
        fun launch(activity: Activity) {
            val intent = Intent(activity, RegisterTypeSelectActivity::class.java)
            activity.startActivity(intent)
            activity.overridePendingTransition(R.anim.slide_in_from_right, R.anim.slide_out_from_left)
        }
    }

    override fun finish() {
        hideKeyboard(binding.root)
        super.finish()
        overridePendingTransition(0, 0)
    }


    override fun getFragmentContainer(): Int = -1
}

