257→    ) {
258→        _state.update { it.copy(isLoading = true) }
259→        var affiliateId: Int? = null
260→        var referralCode: String? = null
261→        when (planData.codeType) {
262→            RegisterCodeType.AffiliateId -> affiliateId = planData.inputCode.toInt()
263→            RegisterCodeType.ReferralCode -> referralCode = planData.inputCode
264→            RegisterCodeType.None -> {}
265→        }
266→        return repo.submitRegistration(
