272→            currency = selectedCurrency.value!!,
273→            affiliateId = affiliateId,
274→            referralCode = referralCode,
275→            isSendPromotionChecked = isSendPromotionChecked,
276→            oAuthUserData = oAuthUserData,
277→            callback = object : SpiResponse<SpiSubmitRegistration.Response>() {
278→                override fun onResponse(
279→                    resp: SpiSubmitRegistration.Response?, status: Status, failCode: FailCode
280→                ): Boolean {
281→                    _state.update { it.copy(isLoading = false) }
282→                    return if (status === Status.SUCCESS) {
283→                        when (valueOrGeneralError(resp!!.code)) {
284→                            ErrorCode.COMM0000 -> {
285→                                val returnStatus = RegisterRepository.Companion.RegisterReturnStatus.fromCode(resp!!.body.returnCode)
286→                                if (returnStatus == RegisterRepository.Companion.RegisterReturnStatus.SUBMIT_SUCCESS) {
287→                                    if (oAuthUserData.oAuthType == Constants.OAuthType.Unknown) {
288→                                        performLogin(userName, pwd)
289→                                    } else {
290→                                        performOAuthLoginAfterRegister(oAuthUserData)
291→                                    }
292→                                    true
293→                                } else {
