313→            override fun onResponse(
314→                resp: SpiLogin.Response?, status: Status, failCode: FailCode
315→            ): Boolean {
316→                _state.update { it.copy(isLoading = false) }
317→                if (status === Status.SUCCESS) {
318→                    return when (ErrorCode.valueOrGeneralError(resp!!.code)) {
319→                        ErrorCode.COMM0000 -> {
320→                            repo.saveLoginSuccessInfo(context, resp.body)
321→                            emitEffect(RegisterEffect.RegisterLoginSuccess)
322→
323→                            // Fetch the general setting by region
324→                            repo.getGeneralSettings(context, Constants.UpdateDeviceInfoEntry.REGISTER)
325→                            true
326→                        }
327→
328→                        else -> {
329→                            emitEffect(RegisterEffect.RegisterLoginFailed)
330→                            true
331→                        }
332→                    }
333→                } else {
334→                    return false
335→                }
336→            }
337→        })
338→    }
339→
340→    private fun performOAuthLoginAfterRegister(
341→        oAuthUserData: OAuthUserData
342→    ) {
343→        _state.update { it.copy(isLoading = true) }
344→        return repo.oAuthLogin(
345→            context, oAuthUserData = oAuthUserData,
346→            callback = object : SpiResponse<SpiLogin.Response>() {
347→                override fun onResponse(
348→                    resp: SpiLogin.Response?, status: Status, failCode: FailCode
349→                ): Boolean {
350→                    _state.update { it.copy(isLoading = false) }
351→                    if (status === Status.SUCCESS) {
352→                        return when (ErrorCode.valueOrGeneralError(resp!!.code)) {
353→                            ErrorCode.COMM0000 -> {
354→                                repo.saveLoginSuccessInfo(context, resp.body)
355→                                emitEffect(RegisterEffect.RegisterLoginSuccess)
356→
357→                                // Fetch the general setting by region
358→                                repo.getGeneralSettings(context, Constants.UpdateDeviceInfoEntry.REGISTER)
359→                                true
360→                            }
361→
362→                            else -> {
363→                                emitEffect(RegisterEffect.RegisterLoginFailed)
364→                                true
365→                            }
366→                        }
367→                    } else {
368→                        return false
369→                    }
370→                }
371→            })
372→    }
373→}
374→
375→// --- UiState: ongoing UI state ---
376→data class RegisterUiState(
377→    val isLoading: Boolean = false,
378→    val legalAge: Int = REGISTER_LEGAL_AGE_DEFAULT,
379→)
380→
381→// --- Effect: one-time events consumed by the View ---
382→sealed interface RegisterEffect {
383→    // Navigation
384→    data object NavigateToLogin : RegisterEffect
385→    data class NavigateToSimpleWeb(val webObject: SimpleWebObject) : RegisterEffect
386→    data class NavigateToSuccessPage(val webObject: RegisterSuccessWebObject) : RegisterEffect
387→    data class NavigateToOAuthRegister(val oAuthUserData: OAuthUserData) : RegisterEffect
388→
389→    // IBaseRegister replacements (previously callback-based)
390→    data object OpenRegionSearch : RegisterEffect
391→    data object OpenCurrencyChooser : RegisterEffect
392→    data object OpenEnterAffiliatePage : RegisterEffect
393→    data object CheckEnableRegisterBtn : RegisterEffect
394→
395→    // Registration results
396→    data class RegisterResponseStatus(val status: RegisterRepository.Companion.RegisterReturnStatus) : RegisterEffect
397→    data object RegisterLoginSuccess : RegisterEffect
398→    data object RegisterLoginFailed : RegisterEffect
399→}
