    override fun googleIdTokenCredentialResponse(tokenCredential: GoogleIdTokenCredential) {
        emitEffect(
            RegisterEffect.NavigateToOAuthRegister(
                OAuthUserData(
                    oAuthType = Constants.OAuthType.Google,
                    oAuthEmail = tokenCredential.id,
                    oAuthId = GoogleOAuthUtil.getOAuthIdForSPI(tokenCredential.idToken),
                    isOAuthEmailVerified = GoogleOAuthUtil.isEmailVerified(tokenCredential.idToken),
                )
            )
        )
    }

    private fun performGetAllRegistrationOptionAndDefault() {
        _state.update { it.copy(isLoading = true) }
        return repo.getRegistrationOption(context, object : SpiResponse<SpiGetRegisterOptions.Response>() {
            override fun onResponse(
                resp: SpiGetRegisterOptions.Response?, status: Status, failCode: FailCode
            ): Boolean {
                _state.update { it.copy(isLoading = false) }
                if (status === Status.SUCCESS) {
                    return when (ErrorCode.valueOrGeneralError(resp!!.code)) {
                        ErrorCode.COMM0000 -> {
                            repo.saveRegionList(context, resp.body.options!!.countries)
                            repo.saveCurrencyList(context, resp.body.options!!.currencies)
                            repo.setEnableReferAFriend(context, resp.body.enableReferAFriend)
                            enableReferAFriend.value = resp.body.enableReferAFriend

                            val isoCodeRegion = repo.getIsoRegion(context)
                            val countryNameRegion = repo.getDefaultRegion(context, resp.body.preference!!.countryName)
                            when {
                                isoCodeRegion != null -> {
                                    selectedRegion.value = isoCodeRegion!!
                                    performGetAgeCurrencyListOfRegion()
                                }

                                countryNameRegion != null -> {
                                    selectedRegion.value = countryNameRegion!!
                                    selectedCurrency.value = repo.getDefaultCurrency(context, resp.body.preference!!.defcurrency)
                                    currencyList = repo.getCurrencyListOfRegion(context, resp.body.preference!!.currencies)
                                    _state.update { it.copy(legalAge = resp.body.preference!!.getLegalAge()) }
                                    isEnableGoogleOAuth.value = RegionUtil.getRegion(context, resp.body.preference!!.region, null).isAllowGoogleOAuth
                                    if (isEnableFacebookOAuth.value != null) isEnableFacebookOAuth.value = RegionUtil.getRegion(context, resp.body.preference!!.region, null).isAllowFacebookOAuth
                                }

                                else -> {
                                    val regionList = repo.getRegionList(context)
                                    if (regionList.isNotEmpty()) {
                                        selectedRegion.value = regionList[0]
                                        performGetAgeCurrencyListOfRegion()
                                    }
                                }
                            }
                            true
                        }

                        else -> false
                    }
                } else {
                    return false
                }
            }
        })
    }

    fun performGetAgeCurrencyListOfRegion() {
        _state.update { it.copy(isLoading = true) }
        return repo.getCurrencyCodeListOfRegion(context, selectedRegion.value!!.code, object : SpiResponse<SpiGetCountryPreference.Response>() {
            override fun onResponse(
                resp: SpiGetCountryPreference.Response?, status: Status, failCode: FailCode
            ): Boolean {
                _state.update { it.copy(isLoading = false) }
                return if (status === Status.SUCCESS) {
                    when (ErrorCode.valueOrGeneralError(resp!!.code)) {
                        ErrorCode.COMM0000 -> {
                            _state.update { it.copy(legalAge = resp.body.getLegalAge()) }

                            selectedCurrency.value = repo.getDefaultCurrency(context, resp.body.defcurrency)
                            currencyList = repo.getCurrencyListOfRegion(context, resp.body.currencies)
                            isEnableGoogleOAuth.value = RegionUtil.getRegion(context, resp.body.region, null).isAllowGoogleOAuth
                            if (isEnableFacebookOAuth.value != null) isEnableFacebookOAuth.value = RegionUtil.getRegion(context, resp.body.region, null).isAllowFacebookOAuth
                            true
                        }

                        else -> false
                    }
                } else {
                    false
                }
            }
        })
    }

    fun performOAuthRegister(
        oAuthUserData: OAuthUserData,
        email: String, userName: String, pwd: String, planData: EnterRegisterPlanData, isSendPromotionChecked: Boolean,
    ) {
        performRegister(
            email = email,
            userName = userName,
            pwd = pwd,
            planData = planData,
            isSendPromotionChecked = isSendPromotionChecked,
            oAuthUserData = oAuthUserData
        )
    }

    fun performRegister(
        email: String, userName: String, pwd: String, planData: EnterRegisterPlanData, isSendPromotionChecked: Boolean,
        oAuthUserData: OAuthUserData = OAuthUserData()
    ) {
        _state.update { it.copy(isLoading = true) }
        var affiliateId: Int? = null
        var referralCode: String? = null
        when (planData.codeType) {
            RegisterCodeType.AffiliateId -> affiliateId = planData.inputCode.toInt()
            RegisterCodeType.ReferralCode -> referralCode = planData.inputCode
            RegisterCodeType.None -> {}
        }
        return repo.submitRegistration(
            context,
            email = email,
            userName = userName,
            pwd = pwd,
            region = selectedRegion.value!!,
            currency = selectedCurrency.value!!,
            affiliateId = affiliateId,
            referralCode = referralCode,
            isSendPromotionChecked = isSendPromotionChecked,
            oAuthUserData = oAuthUserData,
            callback = object : SpiResponse<SpiSubmitRegistration.Response>() {
                override fun onResponse(
                    resp: SpiSubmitRegistration.Response?, status: Status, failCode: FailCode
                ): Boolean {
                    _state.update { it.copy(isLoading = false) }
                    return if (status === Status.SUCCESS) {
                        when (valueOrGeneralError(resp!!.code)) {
                            ErrorCode.COMM0000 -> {
                                val returnStatus = RegisterRepository.Companion.RegisterReturnStatus.fromCode(resp!!.body.returnCode)
                                if (returnStatus == RegisterRepository.Companion.RegisterReturnStatus.SUBMIT_SUCCESS) {
                                    if (oAuthUserData.oAuthType == Constants.OAuthType.Unknown) {
                                        performLogin(userName, pwd)
                                    } else {
                                        performOAuthLoginAfterRegister(oAuthUserData)
                                    }
                                    true
                                } else {
                                    emitEffect(RegisterEffect.RegisterResponseStatus(returnStatus))
                                    false
                                }
                            }

                            else -> {
                                false
                            }
                        }
                    } else {
                        false
                    }
                }
            })
    }

    fun performLogin(userName: String, pwd: String) {
        _state.update { it.copy(isLoading = true) }
        return repo.login(context, userName, pwd, object : SpiResponse<SpiLogin.Response>() {
            override fun onResponse(
                resp: SpiLogin.Response?, status: Status, failCode: FailCode
            ): Boolean {
                _state.update { it.copy(isLoading = false) }
                if (status === Status.SUCCESS) {
                    return when (ErrorCode.valueOrGeneralError(resp!!.code)) {
                        ErrorCode.COMM0000 -> {
                            repo.saveLoginSuccessInfo(context, resp.body)
                            emitEffect(RegisterEffect.RegisterLoginSuccess)

                            // Fetch the general setting by region
                            repo.getGeneralSettings(context, Constants.UpdateDeviceInfoEntry.REGISTER)
                            true
                        }

                        else -> {
                            emitEffect(RegisterEffect.RegisterLoginFailed)
                            true
                        }
                    }
                } else {
                    return false
                }
            }
        })
    }

    private fun performOAuthLoginAfterRegister(
        oAuthUserData: OAuthUserData
    ) {
        _state.update { it.copy(isLoading = true) }
        return repo.oAuthLogin(
            context, oAuthUserData = oAuthUserData,
            callback = object : SpiResponse<SpiLogin.Response>() {
                override fun onResponse(
                    resp: SpiLogin.Response?, status: Status, failCode: FailCode
                ): Boolean {
                    _state.update { it.copy(isLoading = false) }
                    if (status === Status.SUCCESS) {
                        return when (ErrorCode.valueOrGeneralError(resp!!.code)) {
                            ErrorCode.COMM0000 -> {
                                repo.saveLoginSuccessInfo(context, resp.body)
                                emitEffect(RegisterEffect.RegisterLoginSuccess)

                                // Fetch the general setting by region
                                repo.getGeneralSettings(context, Constants.UpdateDeviceInfoEntry.REGISTER)
                                true
                            }

                            else -> {
                                emitEffect(RegisterEffect.RegisterLoginFailed)
                                true
                            }
                        }
                    } else {
                        return false
                    }
                }
            })
    }
}

// --- UiState: ongoing UI state ---
data class RegisterUiState(
    val isLoading: Boolean = false,
    val legalAge: Int = REGISTER_LEGAL_AGE_DEFAULT,
)

// --- Effect: one-time events consumed by the View ---
sealed interface RegisterEffect {
    // Navigation
    data object NavigateToLogin : RegisterEffect
    data class NavigateToSimpleWeb(val webObject: SimpleWebObject) : RegisterEffect
    data class NavigateToSuccessPage(val webObject: RegisterSuccessWebObject) : RegisterEffect
    data class NavigateToOAuthRegister(val oAuthUserData: OAuthUserData) : RegisterEffect

    // IBaseRegister replacements (previously callback-based)
    data object OpenRegionSearch : RegisterEffect
    data object OpenCurrencyChooser : RegisterEffect
    data object OpenEnterAffiliatePage : RegisterEffect
    data object CheckEnableRegisterBtn : RegisterEffect

    // Registration results
    data class RegisterResponseStatus(val status: RegisterRepository.Companion.RegisterReturnStatus) : RegisterEffect
    data object RegisterLoginSuccess : RegisterEffect
    data object RegisterLoginFailed : RegisterEffect
}

