/** key points difference from RegisterActivity
 * 1. email can't edit (only Google)
 * 2. no captcha
 * 3. after changed country, need to check region setting and show different error if needed -> checkByRegionSetting
 * **/
open class OAuthRegisterActivity : BaseBindingHeaderActivity<ActivityOauthRegisterBinding>(),
    IPositiveButtonDialogListener {

    var mData = OAuthUserData()
    val mViewModel: RegisterViewModel by viewModel()

    private var isEmailEdited: Boolean = false
    private var isUsernameEdited: Boolean = false
    private var isPwdEdited: Boolean = false

    override fun getActivityID(): Int {
        return ConstantsBet188.BOTTOM_NAVIGATION_ICON_DEFAULT
    }

    override fun getLayHeaderBinding(): ViewPageHeaderBinding? {
        return binding.layHeader.headerBinding
    }

    override fun getBottomNavigationView(): BottomNavigationView? {
        return null
    }

    override fun getContentView(): Int {
        return R.layout.activity_oauth_register
    }

    override fun onCreateViewBuilder(): BaseActivityOptions.Builder? {
        return super.onCreateViewBuilder()?.setLogoVisible(true)?.setLogoIcon(StyleManager.logoIcon)
            ?.setMenuVisible(true)?.setMarqueeEnable(false)?.setBottomNavigationBarVisible(false)
    }

    override fun initData() {
        super.initData()

        if (intent != null) {
            mData = if (intent.hasExtra(KEY_OAUTH_REGISTER_DATA)) Gson().fromJson(
                intent.getStringExtra(KEY_OAUTH_REGISTER_DATA),
                OAuthUserData::class.java
            ) else OAuthUserData()
        }

        mViewModel.init(this)

        // Collect StateFlow for ongoing UI state
        lifecycleScope.launch {
            repeatOnLifecycle(Lifecycle.State.STARTED) {
                launch { mViewModel.state.collect { render(it) } }
                launch { mViewModel.effects.collect { handleEffect(it) } }
            }
        }

        // Category A: Keep LiveData observers for XML-bound fields
        mViewModel.selectedRegion.observe(this) { region ->
            if (region != null) {
                checkRegion(region)
                checkIsEnableRegisterBtn()
            }
        }

        mViewModel.selectedCurrency.observe(this) { currency ->
            if (currency != null) {
                checkIsEnableRegisterBtn()
            }
        }

        mViewModel.isEnableGoogleOAuth.observe(this) { isEnable ->
            if (mData.oAuthType == Constants.OAuthType.Google) checkByRegionSetting(mData.oAuthType, isEnable)
        }

        mViewModel.isEnableFacebookOAuth.observe(this) { isEnable ->
            if (mData.oAuthType == Constants.OAuthType.Facebook && isEnable != null) checkByRegionSetting(mData.oAuthType, isEnable)
        }

        binding.vm = mViewModel
    }

    private fun render(state: RegisterUiState) {
        if (state.isLoading) showLoadingDialog() else dismissLoadingDialog()
        updateTermAge(state.legalAge)
    }

    private fun handleEffect(effect: RegisterEffect) {
        when (effect) {
            is RegisterEffect.NavigateToLogin -> {
                LoginActivity.launchClearTop(this)
            }

            is RegisterEffect.NavigateToSimpleWeb -> {
                SimpleWebActivity.launch(this, effect.webObject)
            }

            is RegisterEffect.NavigateToSuccessPage -> {
                RegisterSuccessWebActivity.launchClearTop(this, effect.webObject)
            }

            is RegisterEffect.NavigateToOAuthRegister -> {
                OAuthRegisterActivity.launch(this, effect.oAuthUserData)
            }

            is RegisterEffect.OpenRegionSearch -> {
                openRegionSearch()
            }

            is RegisterEffect.OpenCurrencyChooser -> {
                openCurrencyChooser()
            }

            is RegisterEffect.OpenEnterAffiliatePage -> {
                openEnterAffiliatePage()
            }

            is RegisterEffect.CheckEnableRegisterBtn -> {
                checkIsEnableRegisterBtn()
            }

            is RegisterEffect.RegisterResponseStatus -> {
                handleRegisterResponseStatus(effect.status)
            }

            is RegisterEffect.RegisterLoginSuccess -> {
                openUpLockPatternSetting()
            }

            is RegisterEffect.RegisterLoginFailed -> {
                DialogUtil.showSimpleDialog(
                    this,
                    getString(UiStr.TXTJOINUSSIGNUP),
                    getString(UiStr.MSGJOINUSFAIL),
                    getString(UiStr.TXTBTNCOMOK),
                    0
                )
            }
        }
    }

    private fun handleRegisterResponseStatus(responseStatus: RegisterRepository.Companion.RegisterReturnStatus) {
        when (responseStatus) {
            RegisterRepository.Companion.RegisterReturnStatus.USERNAME_EXIST -> {
                binding.scrollView.smoothScrollTo(0, 0)
                binding.usernameLayout.error = getString(UiStr.HELPJOINUSUSERIDEXIST)
            }

            RegisterRepository.Companion.RegisterReturnStatus.EMAIL_USERNAME_EXIST -> {
                binding.scrollView.smoothScrollTo(0, 0)
                if (mData.isEmailEditable) binding.emailLayout.error = getString(UiStr.MSGJOINUSEMAILEXISTED)
                binding.usernameLayout.error = getString(UiStr.HELPJOINUSUSERIDEXIST)
            }

            RegisterRepository.Companion.RegisterReturnStatus.EMAIL_EXIST,
            RegisterRepository.Companion.RegisterReturnStatus.OAUTH_FAIL -> {
                if (mData.isEmailEditable) {
                    binding.scrollView.smoothScrollTo(0, 0)
                    binding.emailLayout.error = getString(UiStr.MSGJOINUSEMAILEXISTED)
                } else {
                    showOAuthFailPopup()
                }
            }

            RegisterRepository.Companion.RegisterReturnStatus.OAUTH_ID_EXIST -> {
                showOAuthFailPopup()
            }

            RegisterRepository.Companion.RegisterReturnStatus.FAIL -> {
                DialogUtil.showSimpleDialog(
                    this,
                    getString(UiStr.TXTJOINUSSIGNUP),
                    getString(UiStr.MSGJOINUSFAIL),
                    getString(UiStr.TXTBTNCOMOK),
                    0
                )
            }

            RegisterRepository.Companion.RegisterReturnStatus.USERNAME_SAME_AS_PASSWORD -> {
                DialogUtil.showSimpleDialog(
                    this,
                    getString(UiStr.TXTJOINUSSIGNUP),
                    getString(UiStr.USERNAMEANDPASSWORDSAMEERROR),
                    getString(UiStr.TXTBTNCOMOK),
                    0
                )
            }

            else -> {}
        }

        if (responseStatus != RegisterRepository.Companion.RegisterReturnStatus.SUBMIT_SUCCESS) {
            checkIsEnableRegisterBtn()
        }
    }

    override fun initView() {
        super.initView()
        getHeaderLoginBtn()!!.visibility = View.VISIBLE
        getHeaderLoginBtn()!!.setOnClickListener { mViewModel.onLoginClick(getHeaderLoginBtn() as View) }

        binding.constraintLayout.setOnClickListener { binding.scrollView.clearFocus() }  //for force check affId

        // Disable copy paste for EditText
        binding.username.disableCopyPaste()
        binding.pwd.disableCopyPaste()

        if (mData.isEmailEditable) {
            binding.email.isEnabled = true

            binding.email.disableCopyPaste()
            binding.email.addTextChangedListener(object : TextWatcher {
                override fun beforeTextChanged(s: CharSequence, start: Int, count: Int, after: Int) {
                    binding.emailLayout.error = ""
                }

                override fun onTextChanged(s: CharSequence, start: Int, before: Int, count: Int) {}
                override fun afterTextChanged(editable: Editable) {
                    isEmailEdited = true
                    val inputStr = editable.toString().trim()
                    if (!CommonUtils.isEmailFormatValid(inputStr)) {
                        binding.emailLayout.error = getString(UiStr.TIPJOINUSVALIDEMAIL)
                    }

                    checkIsEnableRegisterBtn()
                }
            })

            binding.email.setOnFocusChangeListener { _, hasFocus ->
                if (!hasFocus && isEmailEdited) {
                    if ((binding.email.text!!.isEmpty())) binding.emailLayout.error =
                        getString(UiStr.HELPJOINUSREQUIRED)
                }
            }
        } else {
            //set init data before set click listener
            if (!TextUtils.isEmpty(mData.oAuthEmail)) binding.email.setText(mData.oAuthEmail, false)

            binding.email.isEnabled = false
            binding.emailLayout.boxStrokeWidth = 0
            binding.emailLayout.boxStrokeWidthFocused = 0
        }

        binding.username.addTextChangedListener(object : TextWatcher {
            override fun beforeTextChanged(s: CharSequence, start: Int, count: Int, after: Int) {}
            override fun onTextChanged(s: CharSequence, start: Int, before: Int, count: Int) {}
            override fun afterTextChanged(editable: Editable) {
                isUsernameEdited = true
                val inputStr = editable.toString().trim()
                if (inputStr.length < 5 || inputStr.length > 15) {
                    binding.usernameLayout.error = getString(UiStr.TIPJOINUSUSERIDREQUIRE)
                } else if (!CommonUtils.isLoginUserNameValid(inputStr)) {
                    binding.usernameLayout.error = getString(UiStr.HELPJOINUSUSERIDREQUIRE)
                } else {
                    binding.usernameLayout.error = ""
                    binding.usernameLayout.helperText = getString(UiStr.TIPJOINUSUSERIDREQUIRE)
                }

                updatePasswordErrorHint(true)
                checkIsEnableRegisterBtn()
            }
        })
        binding.username.setOnFocusChangeListener { _, hasFocus ->
            if (!hasFocus && isUsernameEdited) {
                if ((binding.username.text!!.isEmpty())) binding.usernameLayout.error =
                    getString(UiStr.HELPJOINUSREQUIRED)
            }
        }

        binding.pwd.addTextChangedListener(object : TextWatcher {
            override fun beforeTextChanged(s: CharSequence, start: Int, count: Int, after: Int) {}
            override fun onTextChanged(s: CharSequence, start: Int, before: Int, count: Int) {}
            override fun afterTextChanged(editable: Editable) {
                isPwdEdited = true
                updatePasswordErrorHint(false)
                checkIsEnableRegisterBtn()
            }
        })

        binding.pwd.setOnFocusChangeListener { _, hasFocus ->
            if (!hasFocus && isPwdEdited) {
                if ((binding.pwd.text!!.isEmpty())) binding.pwdLayout.error =
                    getString(UiStr.HELPJOINUSREQUIRED)
            }
        }

        //term privacy
        val termPrivacyMsgStr = SpannableString(getString(UiStr.MSGNEWJOINUSSENDUPDATEEMAIL))
        val privacySpan: ClickableSpan = object : ClickableSpan() {
            override fun onClick(textView: View) {
                binding.scrollView.clearFocus()  //for force check affId
                mViewModel.openSimpleWeb(
                    textView,
                    getString(UiStr.NAVPRIVACYPOLICY),
                    getString(R.string.urlPrivacyPolicy)
                )
            }

            override fun updateDrawState(ds: TextPaint) {
                ds.isUnderlineText = false // set to false to remove underline
            }
        }
        val privacyStr = getString(UiStr.MSGLINKUPDATEEMAIL)
        if (termPrivacyMsgStr.toString().contains(privacyStr)) {
            val end = privacyStr.length + termPrivacyMsgStr.toString().indexOf(privacyStr)
            termPrivacyMsgStr.setSpan(
                privacySpan,
                termPrivacyMsgStr.toString().indexOf(privacyStr),
                end,
                Spanned.SPAN_EXCLUSIVE_EXCLUSIVE
            )
            termPrivacyMsgStr.setSpan(
                ForegroundColorSpan(resources.getColor(R.color.card_blue_color)),
                termPrivacyMsgStr.toString().indexOf(privacyStr),
                end,
                Spanned.SPAN_EXCLUSIVE_EXCLUSIVE
            )
            termPrivacyMsgStr.setSpan(
                StyleSpan(Typeface.BOLD),
                termPrivacyMsgStr.toString().indexOf(privacyStr),
                end,
                Spanned.SPAN_EXCLUSIVE_EXCLUSIVE
            )
        }

        //enable ClickableSpan
        binding.sendPromotionMsg.movementMethod = LinkMovementMethod.getInstance()
        binding.sendPromotionMsg.text = termPrivacyMsgStr
        binding.sendPromotionMsg.setOnClickListener { binding.scrollView.clearFocus() }  //for force check affId
        binding.checkSendPromotion.setOnCheckedChangeListener { _, _ ->
            binding.scrollView.clearFocus()
        }

        updateTermAge(mViewModel.state.value.legalAge)

        //btn
        binding.btnRegister.setOnClickListener {
            mViewModel.performOAuthRegister(
                oAuthUserData = mData,
                email = binding.email.text.toString(),
                userName = binding.username.text.toString(),
                pwd = binding.pwd.text.toString(),
                planData = mViewModel.affiliateData,
                isSendPromotionChecked = binding.checkSendPromotion.isChecked
            )
        }

        binding.footerView.setDataView(FooterParameter(this))
    }

    private fun updatePasswordErrorHint(fromUsernameFieldChanged: Boolean) {
        val username = binding.username.text.toString()
        val password = binding.pwd.text.toString()
        val isPasswordValid = CommonUtils.isPasswordValid(password)

        when {
            fromUsernameFieldChanged && isPasswordValid -> {
                binding.pwdLayout.error = if (username == password) {
                    getString(UiStr.USERNAMEANDPASSWORDSAMEERROR)
                } else {
                    ""
                }
            }

            !fromUsernameFieldChanged -> {
                binding.pwdLayout.error = if (!isPasswordValid) {
                    getString(UiStr.HELPJOINUSPASSWORD)
                } else if (username == password) {
                    getString(UiStr.USERNAMEANDPASSWORDSAMEERROR)
                } else {
                    ""
                }
            }
        }
    }

    private fun showOAuthFailPopup() {
        val notifyData = IconNotifyDialogFragment.IconNotifyObject(
            R.mipmap.ic_fail_active,
            getString(UiStr.TXTAUTHENTICATIONFAILED),
            getString(UiStr.MSGSIGNWITHDIFFERENTACCOUNT),
            getString(UiStr.TXTBTNCOMOK)
        )

        IconNotifyDialogFragment.newInstance(notifyData)
            .setListener(this)
            .show(
                supportFragmentManager,
                IconNotifyDialogFragment::class.java.simpleName
            )
    }

    private fun updateTermAge(age: Int = REGISTER_LEGAL_AGE_DEFAULT) {
        //term age
        val term21MsgStr =
            SpannableString(getString(UiStr.MSGCONFIRMIMATLEASTAGE, age.toString()))
        val age21Span: ClickableSpan = object : ClickableSpan() {
            override fun onClick(textView: View) {
                binding.scrollView.clearFocus()  //for force check affId
                mViewModel.openSimpleWeb(
                    textView,
                    getString(UiStr.NAVTERMSANDCONDITIONS),
                    getString(R.string.urlTermsAndConditions)
                )
            }

            override fun updateDrawState(ds: TextPaint) {
                ds.isUnderlineText = false // set to false to remove underline
            }
        }
        val term21Str = getString(UiStr.MSGLINKATLEAST21AGE)
        if (term21MsgStr.toString().contains(term21Str)) {
            val end = term21Str.length + term21MsgStr.toString().indexOf(term21Str)
            term21MsgStr.setSpan(
                age21Span,
                term21MsgStr.toString().indexOf(term21Str),
                end,
                Spanned.SPAN_EXCLUSIVE_EXCLUSIVE
            )
            term21MsgStr.setSpan(
                ForegroundColorSpan(resources.getColor(R.color.card_blue_color)),
                term21MsgStr.toString().indexOf(term21Str),
                end,
                Spanned.SPAN_EXCLUSIVE_EXCLUSIVE
            )
            term21MsgStr.setSpan(
                StyleSpan(Typeface.BOLD),
                term21MsgStr.toString().indexOf(term21Str),
                end,
                Spanned.SPAN_EXCLUSIVE_EXCLUSIVE
            )
        }
        binding.termAgeMsg.movementMethod = LinkMovementMethod.getInstance()  //enable ClickableSpan
        binding.termAgeMsg.text = term21MsgStr
        binding.termAgeMsg.setOnClickListener { binding.scrollView.clearFocus() }  //for force check affId
    }

    override fun onBaseMenuClick() {
        binding.scrollView.clearFocus()  //for force check affId
        super.onBaseMenuClick()
    }

    fun checkRegion(region: RegisterRegionObject) {
        if (!region.isRegistrationEnable()) {
            binding.regionError.visibility = View.VISIBLE
            binding.regionError.text = getString(UiStr.HELPJOINUSINACTIVEJURISDICTION)

            binding.selectionLayout.setBackgroundResource(R.drawable.bg_capsule_holo_red)
            binding.lineV.setBackgroundColor(ContextCompat.getColor(this, R.color.orange_flamingo))
        } else {
            binding.regionError.visibility = View.GONE

            binding.selectionLayout.setBackgroundResource(R.drawable.bg_capsule_holo_gray)
            binding.lineV.setBackgroundColor(ContextCompat.getColor(this, R.color.gray_dc))
        }
    }

    private fun checkByRegionSetting(oAuthType: Constants.OAuthType, isEnable: Boolean) {
        if (binding.regionError.isVisible) return

        if (oAuthType != Constants.OAuthType.Unknown && !isEnable) {
            binding.regionError.visibility = View.VISIBLE
            binding.regionError.text = getString(UiStr.MSGOAUTHUNABLESIGNUP)

            binding.selectionLayout.setBackgroundResource(R.drawable.bg_capsule_holo_red)
            binding.lineV.setBackgroundColor(ContextCompat.getColor(this, R.color.orange_flamingo))
        }
    }

    fun checkIsEnableRegisterBtn() {
        binding.btnRegister.isEnabled =
            (!TextUtils.isEmpty(binding.email.text) && TextUtils.isEmpty(binding.emailLayout.error)
                    && !TextUtils.isEmpty(binding.username.text)
                    && TextUtils.isEmpty(binding.usernameLayout.error)
                    && !TextUtils.isEmpty(binding.pwd.text)
                    && TextUtils.isEmpty(binding.pwdLayout.error)
                    && !TextUtils.isEmpty(binding.region.text)
                    && !TextUtils.isEmpty(binding.currency.text) && binding.regionError.visibility != View.VISIBLE)
    }

    fun openEnterAffiliatePage() {
        binding.scrollView.clearFocus()

        val affIntent = EnterAffiliateActivity.getSingleTopIntent(this, mViewModel.affiliateData)
        enterAffiliateLaunchForResult.launch(affIntent)
    }

    private val enterAffiliateLaunchForResult = registerForActivityResult(
        ActivityResultContracts.StartActivityForResult()
    ) { result ->
        if (result.resultCode == Activity.RESULT_OK) {
            val dataIntent = result.data
            val affData = if (dataIntent != null) Gson().fromJson(
                dataIntent.getStringExtra(EnterAffiliateActivity.KEY_ENTER_AFFILIATE_DATA),
                EnterRegisterPlanData::class.java
            ) else EnterRegisterPlanData()

            mViewModel.affiliateData = affData
            val title = when (affData.codeType) {
                RegisterCodeType.AffiliateId -> getString(
                    R.string.str_colon_space_str,
                    getString(UiStr.TITAFFILIATESID),
                    affData.inputCode
                )

                RegisterCodeType.ReferralCode -> getString(
                    R.string.str_colon_space_str,
                    getString(UiStr.TITREFERRALCODE),
                    affData.inputCode
                )

                RegisterCodeType.None -> ""
            }
            val spannableStr = SpannableStringBuilder(title)
            if (!TextUtils.isEmpty(affData.inputCode)) {
                spannableStr.setSpan(
                    StyleSpan(Typeface.BOLD),
                    title.indexOf(affData.inputCode, ignoreCase = true),
                    title.indexOf(affData.inputCode, ignoreCase = true) + affData.inputCode.length,
                    Spannable.SPAN_EXCLUSIVE_EXCLUSIVE
                )
            }

            binding.affiliateTitle.text = spannableStr
            binding.affiliateTitle.visibility =
                if (TextUtils.isEmpty(affData.inputCode)) View.GONE else View.VISIBLE
            binding.btnAff.text = if (TextUtils.isEmpty(affData.inputCode)) {
                if (mViewModel.isEnableReferAFriend(this@OAuthRegisterActivity))
                    getString(UiStr.TXTHAVEAFFIDORREFCODE)
                else
                    getString(UiStr.TXTHAVEAFFILIATECODE)
            } else getString(UiStr.TXTHAVEAFFILIATECHANGE)
        }
    }

    fun openRegionSearch() {
        binding.scrollView.clearFocus()

        val intent = RegionSearchActivity.getLaunchIntent(this@OAuthRegisterActivity)
        regionSearchActivityLaunchForResult.launch(intent)
    }

    private var regionSearchActivityLaunchForResult = registerForActivityResult(
        ActivityResultContracts.StartActivityForResult()
    ) { result ->
        val resultDataIntent: Intent? = result.data
        if (result.resultCode == Activity.RESULT_OK) {
            val oriData = resultDataIntent?.getStringExtra(KEY_SELECTED_REGION) ?: ""
            mViewModel.selectedRegion.value =
                GsonUtil.getGson().fromJson(oriData, RegisterRegionObject::class.java)

            //update currency
            mViewModel.performGetAgeCurrencyListOfRegion()
        }
    }

    fun openCurrencyChooser() {
        binding.scrollView.clearFocus()

        if (!mViewModel.currencyList.isNullOrEmpty()) {
            val dataList: MutableList<ChooserItem<CurrencyObject>> = ArrayList()

            for (data in mViewModel.currencyList) dataList.add(ChooserItem(data.name, data))

            val viewBinding: ViewPopupChooserBinding = DataBindingUtil.inflate(
                getSystemService(Context.LAYOUT_INFLATER_SERVICE) as LayoutInflater,
                R.layout.view_popup_chooser,
                null,
                false
            )
            val popupWindow = ListPopupWindow<CurrencyObject>(this, viewBinding)

            popupWindow.setChooserAdapter(dataList, mViewModel.selectedCurrency)
            popupWindow.show(binding.currency, 0, AndroidUtils.convertDpToPixel(1f))
        } else {
            Toast.makeText(this, getString(UiStr.NODATA), Toast.LENGTH_SHORT).show()
        }
    }

    private fun openUpLockPatternSetting() {
        val intent = Intent(this@OAuthRegisterActivity, LockPatternActivity::class.java).apply {
            putExtras(
                bundleOf(
                    LOCK_PATTERN_FUNCTION_KEY to LockPatternFunction.SET_KEY
                )
            )
        }
        lockPatternActivityLaunchForResult.launch(intent)
    }

    private var lockPatternActivityLaunchForResult = registerForActivityResult(
        ActivityResultContracts.StartActivityForResult()
    ) { result ->
        val resultDataIntent: Intent? = result.data
        if (result.resultCode == Activity.RESULT_OK) {
            val lockPattenKey =
                resultDataIntent?.getStringExtra(RESULT_DATA_SAVE_KEY) ?: ""
            mViewModel.saveLockPattern(lockPattenKey)
            mViewModel.openSuccessPage()
            finish()
        } else if (result.resultCode == Activity.RESULT_CANCELED) {
            //need to clear saved info
            CommonUtils.handleUserLogout(this, true)
        }
    }

    override fun onPositiveButtonClicked(requestCode: Int) {
        when (requestCode) {
            IconNotifyDialogFragment.DIALOG_ICON_NOTIFY_RESULT_OK -> {
                finish()
            }
        }
    }

    companion object {
        const val KEY_OAUTH_REGISTER_DATA = "KEY_OAUTH_REGISTER_DATA"

        fun launch(activity: Activity, data: OAuthUserData) {
            val intent = Intent(activity, OAuthRegisterActivity::class.java)
            intent.putExtra(KEY_OAUTH_REGISTER_DATA, Gson().toJson(data))
            activity.startActivity(intent)
            activity.overridePendingTransition(
                R.anim.slide_in_from_right,
                R.anim.slide_out_from_left
            )
        }
    }

    override fun finish() {
        mViewModel.clearCache()
        hideKeyboard(binding.root)
        super.finish()
    }

    override fun getFragmentContainer(): Int = -1
}

