package com.xuenn.bet188.revamp.view.register

import android.app.Activity
import android.content.Intent
import android.text.TextUtils
import android.webkit.JavascriptInterface
import com.xuenn.bet188.R
import com.xuenn.bet188.comm.PageHistoryManager
import com.xuenn.bet188.comm.config.ConstantsBet188
import com.xuenn.bet188.comm.config.ConstantsUtils
import com.xuenn.bet188.comm.dialog.DialogUtil
import com.xuenn.bet188.comm.dialog.iface.INegativeButtonDialogListener
import com.xuenn.bet188.comm.dialog.iface.IPositiveButtonDialogListener
import com.xuenn.bet188.data.Bet188SharePreferences
import com.xuenn.bet188.databinding.ActivityRegisterSuccessWebBinding
import com.xuenn.bet188.databinding.ViewPageHeaderBinding
import com.xuenn.bet188.interfaces.WebView188JS
import com.xuenn.bet188.revamp.model.data.RegisterSuccessWebObject
import com.xuenn.bet188.revamp.model.data.UiStr
import com.xuenn.bet188.revamp.model.data.repo.StringsRepository
import com.xuenn.bet188.revamp.utils.GsonUtil
import com.xuenn.bet188.revamp.utils.WebViewUtils.commonConfig
import com.xuenn.bet188.revamp.view.JsTitleWebActivity.Companion.POPUP_NEED_LOGIN
import com.xuenn.bet188.revamp.view.base.BaseActivityOptions
import com.xuenn.bet188.revamp.view.base.BaseBindingHeaderActivity
import com.xuenn.bet188.revamp.view.login.LoginActivity
import com.xuenn.bet188.revamp.viewmodel.WebViewModel
import com.xuenn.bet188.revamp.widget.BottomNavigationView
import org.koin.androidx.viewmodel.ext.android.viewModel


open class RegisterSuccessWebActivity : BaseBindingHeaderActivity<ActivityRegisterSuccessWebBinding>(), IPositiveButtonDialogListener, INegativeButtonDialogListener {

    protected val mViewModel: WebViewModel by viewModel()

    protected var mData = RegisterSuccessWebObject()

    override fun getActivityID(): Int {
        return ConstantsBet188.BOTTOM_NAVIGATION_ICON_DEFAULT
    }

    override fun getLayHeaderBinding(): ViewPageHeaderBinding? {
        return binding.layHeader.headerBinding
    }

    override fun getBottomNavigationView(): BottomNavigationView? {
        return null
    }

    override fun getContentView(): Int {
        return R.layout.activity_register_success_web
    }

    override fun getFragmentContainer(): Int = -1

    override fun onCreateViewBuilder(): BaseActivityOptions.Builder? {
        return super.onCreateViewBuilder()
            ?.setBottomNavigationBarVisible(false)
            ?.setDisplayTitleVisible(true)
    }

    override fun onNewIntent(intent: Intent?) {
        super.onNewIntent(intent)
        setIntent(intent)
        initData()
        initView()
    }


    override fun initData() {
        super.initData()

        if (intent != null) {
            mData = if (intent.hasExtra(KEY_JS_TITLE_WEB_DATA)) GsonUtil.getGson().fromJson(
                intent.getStringExtra(KEY_JS_TITLE_WEB_DATA),
                RegisterSuccessWebObject::class.java
            ) else RegisterSuccessWebObject()
        }

        mViewModel.init(this)
    }

    override fun initView() {
        super.initView()

        binding.mainWeb.commonConfig()
        mViewModel.webChromeClient(binding.mainWeb)
        mViewModel.webViewClient(binding.mainWeb)
        binding.mainWeb.addJavascriptInterface(object : WebView188JS(this) {

            @Override
            override fun onRedirect(type: NATIVE_PAGE?, intent: Intent?) {
                if (intent != null) {
                    finish()
                    startActivity(intent)
                }
                super.onRedirect(type, intent)
            }

            override fun preRedirect(type: NATIVE_PAGE?) {
                if (type == NATIVE_PAGE.sbk
                    && !Bet188SharePreferences.getInstance(this@RegisterSuccessWebActivity).isLoginSuccess
                ) {
                    DialogUtil.showTwoButtonDialog(
                        this@RegisterSuccessWebActivity,
                        "", StringsRepository.getString(UiStr.MSGPLEASELOGIN),
                        StringsRepository.getString(UiStr.TXTBTNLOGIN).toUpperCase(),
                        StringsRepository.getString(UiStr.BTNCANCEL), POPUP_NEED_LOGIN
                    )

                } else {
                    super.preRedirect(type)
                }
            }

            @Override
            @JavascriptInterface
            override fun webViewTitle(titleStr: String) {
                runOnUiThread {
                    binding.layHeader.headerBinding.viewProductName.text = titleStr

                    if (!TextUtils.isEmpty(binding.layHeader.headerBinding.viewProductName.text)) {
                        binding.layHeader.headerBinding.viewProductName.setOnClickListener { onBaseToolbarTitleClick() }
                    }
                }

            }
        }, ConstantsBet188.JS_BRIDGE_NAME)

        if (mData.fullUrl.isNotEmpty())
            binding.mainWeb.loadUrl(mData.fullUrl, mData.headers)

    }

    override fun onPositiveButtonClicked(requestCode: Int) {
        when (requestCode) {
            POPUP_NEED_LOGIN -> LoginActivity.launchClearTop(this)
        }
        super.onPositiveButtonClicked(requestCode)
    }

    override fun onNegativeButtonClicked(requestCode: Int) {
        when (requestCode) {
            POPUP_NEED_LOGIN -> if (binding.mainWeb.canGoBack()) binding.mainWeb.goBack() else finish()
        }
    }

    companion object {
        const val KEY_JS_TITLE_WEB_DATA = "KEY_JS_TITLE_WEB_DATA"

        fun launchClearTop(activity: Activity, data: RegisterSuccessWebObject) {
            val intent = Intent(activity, RegisterSuccessWebActivity::class.java)
            intent.putExtra(KEY_JS_TITLE_WEB_DATA, GsonUtil.getGson().toJson(data))
            intent.addFlags(Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TASK)
            activity.startActivity(intent)
        }
    }

}
